def parse_time_range(value: str | None = None) -> dict | None:
    """Helper function for parameter transformation"""
    if value is None:
        return None
    if '/' not in value:
        raise ValueError('Time range must be in format "from/to"') from None
    try:
        parts = value.split('/', 1)
        if len(parts) != 2:
            raise ValueError('Time range must contain exactly one "/" separator') from None
        from_ts, to_ts = parts
        if not from_ts or not to_ts:
            raise ValueError('Both from and to timestamps must be non-empty') from None
        return {'from': from_ts, 'to': to_ts}
    except ValueError:
        raise

def build_incident_query(facet_filters: list[dict] | None = None, combine_operator: str | None = None) -> str | None:
    """Helper function for parameter transformation"""
    if facet_filters is None:
        return None

    if not facet_filters:
        return None

    operator = (combine_operator or 'AND').upper()
    if operator not in ('AND', 'OR'):
        raise ValueError(f"combine_operator must be 'AND' or 'OR', got '{operator}'") from None

    query_parts = []
    for facet_filter in facet_filters:
        if not isinstance(facet_filter, dict):
            raise ValueError(f"Each facet_filter must be a dict, got {type(facet_filter)}") from None
        
        facet = facet_filter.get('facet')
        values = facet_filter.get('values', [])
        
        if not facet:
            raise ValueError("Each facet_filter must have a 'facet' key") from None
        
        if not values:
            raise ValueError(f"Facet '{facet}' has no values") from None
        
        if len(values) == 1:
            query_parts.append(f"{facet}:{values[0]}")
        else:
            values_str = ' OR '.join(values)
            query_parts.append(f"{facet}:({values_str})")

    return f" {operator} ".join(query_parts)

def parse_impact_interval(value: str | None = None) -> dict | None:
    """Helper function for parameter transformation"""
    if value is None:
        return None
    parts = value.split('/')
    if len(parts) != 2:
        raise ValueError('Invalid ISO 8601 interval format; expected "start/end"') from None
    return {'start_at': parts[0], 'end_at': parts[1]}

def build_tag_filter_expression(tag_filters: list[dict] | None = None, tag_filter_logic: str | None = None, tag_wildcards_enabled: bool | None = None) -> str | None:
    """Helper function for parameter transformation"""
    if tag_filters is None and tag_filter_logic is None and tag_wildcards_enabled is None:
        return None

    try:
        if not tag_filters:
            return None
        
        logic = (tag_filter_logic or 'AND').upper()
        if logic not in ('AND', 'OR'):
            raise ValueError(f"tag_filter_logic must be 'AND' or 'OR', got '{logic}'")
        
        expressions = []
        for f in tag_filters:
            if not isinstance(f, dict) or 'key' not in f or 'value' not in f:
                raise ValueError("Each tag filter must have 'key' and 'value' fields")
            
            key = str(f['key']).strip()
            value = str(f['value']).strip()
            operator = str(f.get('operator', 'AND')).upper()
            
            if not key or not value:
                raise ValueError("Tag key and value cannot be empty")
            
            if operator == 'IN':
                values = [v.strip() for v in value.split(',')]
                expr = f"{key}:({' OR '.join(values)})"
            else:
                if tag_wildcards_enabled and '*' in value:
                    expr = f"{key}:{value}"
                else:
                    expr = f"{key}:{value}"
            
            expressions.append(expr)
        
        result = f" {logic} ".join(expressions)
        return result
    except (KeyError, TypeError, AttributeError) as e:
        raise ValueError(f"Failed to build tag filter expression: {e}") from e

def build_notification_filters(filter_text: str | None = None, filter_tags: list[str] | None = None, filter_recipients: list[str] | None = None) -> str | None:
    """Helper function for parameter transformation"""
    if filter_text is None and filter_tags is None and filter_recipients is None:
        return None

    try:
        filters_dict = {}
        if filter_text is not None:
            filters_dict['text'] = filter_text
        if filter_tags is not None:
            filters_dict['tags'] = filter_tags
        if filter_recipients is not None:
            filters_dict['recipients'] = filter_recipients
        return json.dumps(filters_dict)
    except Exception as e:
        raise ValueError(f"Failed to build notification filters: {e}") from e

def build_filter_query(filter_severity: str | None = None, filter_risk_score_min: float | None = None, filter_risk_score_max: float | None = None, filter_custom_attribute: str | None = None) -> str | None:
    """Helper function for parameter transformation"""
    if all(v is None for v in [filter_severity, filter_risk_score_min, filter_risk_score_max, filter_custom_attribute]):
        return None

    query_parts = []

    if filter_severity is not None:
        query_parts.append(f"severity:{filter_severity}")


    if filter_risk_score_min is not None:
        query_parts.append(f"riskScore:[{filter_risk_score_min} TO *]")

    if filter_risk_score_max is not None:
        query_parts.append(f"riskScore:[* TO {filter_risk_score_max}]")

    if filter_custom_attribute is not None:
        query_parts.append(filter_custom_attribute)

    return " AND ".join(query_parts)

def build_rule_query(rule_filters: list[dict] | None = None, rule_logic: str | None = None) -> str | None:
    """Helper function for parameter transformation"""
    if rule_filters is None and rule_logic is None:
        return None

    if not rule_filters:
        return None

    logic = (rule_logic or 'AND').upper()
    if logic not in ('AND', 'OR'):
        raise ValueError(f"rule_logic must be 'AND' or 'OR', got '{logic}'") from None

    valid_fields = {'name', 'type', 'severity', 'status', 'tag'}
    operator_map = {
        'equals': ':',
        'contains': ':*',
        'matches': '~'
    }

    query_parts = []
    for f in rule_filters:
        if not isinstance(f, dict):
            raise ValueError(f"Each filter must be a dict, got {type(f)}") from None
        field = f.get('field', '').strip().lower()
        operator = f.get('operator', 'equals').lower()
        value = f.get('value', '').strip()
        
        if not field or not value:
            raise ValueError("Each filter must have non-empty 'field' and 'value'") from None
        
        if field not in valid_fields:
            raise ValueError(f"Unknown field '{field}'. Valid: {valid_fields}") from None
        
        if operator not in operator_map:
            raise ValueError(f"Unknown operator '{operator}'. Valid: {list(operator_map.keys())}") from None
        
        op_symbol = operator_map[operator]
        query_parts.append(f"{field}{op_symbol}{value}")

    if not query_parts:
        return None

    return f" {logic} ".join(query_parts)

def parse_schedule(value: str | None = None) -> dict | None:
    """Helper function for parameter transformation"""
    if value is None:
        return None
    if '|' not in value:
        raise ValueError('Schedule must be formatted as "start|rrule"') from None
    parts = value.split('|', 1)
    if len(parts) != 2:
        raise ValueError('Schedule must contain exactly one pipe separator') from None
    start_val, rrule_val = parts
    if not start_val.strip():
        raise ValueError('Start date cannot be empty') from None
    if not rrule_val.strip():
        raise ValueError('RRULE cannot be empty') from None
    return {'start': start_val, 'rrule': rrule_val}

def parse_rfc5322_author(value: str | None = None) -> dict | None:
    """Helper function for parameter transformation"""
    if value is None:
        return None
    if '<' not in value or '>' not in value:
        raise ValueError('Invalid RFC 5322 format: expected "Name <email>"') from None
    try:
        name_part = value[:value.index('<')].strip()
        email_part = value[value.index('<')+1:value.index('>')].strip()
        return {'author_name': name_part, 'author_email': email_part}
    except (ValueError, IndexError) as e:
        raise ValueError(f'Failed to parse RFC 5322 author string: {value}') from e

def _check_unique_items(v: list) -> list:
    """Validate that array items are unique (OAS uniqueItems: true)."""
    seen = []
    for item in v:
        if item in seen:
            raise ValueError("array items must be unique")
        seen.append(item)
    return v

def _serialize_query(params: dict[str, Any], styles: dict[str, tuple[str, bool]]) -> dict[str, Any]:
    """Serialize query params per OAS style/explode rules."""
    result: dict[str, Any] = {}
    for key, value in params.items():
        if key not in styles:
            result[key] = value
            continue
        style, explode = styles[key]
        if isinstance(value, list):
            if style == "pipeDelimited":
                result[key] = "|".join(str(v) for v in value)
            elif style == "spaceDelimited":
                result[key] = " ".join(str(v) for v in value)
            elif not explode:
                result[key] = ",".join(str(v) for v in value)
            else:
                result[key] = value
        elif isinstance(value, dict):
            if style == "deepObject":
                for k, v in value.items():
                    result[f"{key}[{k}]"] = v
            elif not explode:
                result[key] = ",".join(f"{k},{v}" for k, v in value.items())
            else:
                result.update(value)
        else:
            result[key] = value
    return result

def _log_tool_invocation(tool_name: str, method: str, path: str, request_id: str) -> None:
    """Log tool invocation."""
    logging.info(
        f"Tool invoked: {tool_name}",
        extra={
            "request_id": request_id,
            "tool": tool_name,
            "method": method,
            "path": path,
            "timeout": DEFAULT_TIMEOUT
        }
    )

def _build_path(
    template: str,
    path_params: dict[str, Any],
) -> str:
    """Build path from template and parameters.

    Args:
        template: Path template with {param} placeholders
        path_params: Dictionary of parameter names to values

    Returns:
        Path with all  placeholders replaced

    Example:
        _build_path("/files/{fileId}/copy", {"fileId": "abc123"})
        Returns: "/files/abc123/copy"
    """
    result = template
    for key, value in path_params.items():
        result = result.replace("{" + key + "}", str(value))
    # Normalize double slashes that occur when a path param value itself starts
    # with "/" and the template already has a preceding "/" (e.g. "/{path}" + "/foo")
    while "//" in result:
        result = result.replace("//", "/")
    return result

async def _execute_tool_request(
    tool_name: str,
    method: str,
    path: str,
    request_id: str,
    params: dict[str, Any] | None = None,
    body: Any = None,
    body_content_type: str | None = None,
    headers: dict[str, str] | None = None,
    cookies: dict[str, str] | None = None,
    raw_querystring: str | None = None,
) -> tuple[dict[str, Any], int]:
    """
    Execute tool request with timeout handling and metrics recording.

    Returns:
        Tuple of (normalized_response_data, status_code).
        Response data is normalized to dict format for Pydantic validation.
        Status code: HTTP status code from the API response.
    """
    start_time = time.time()
    try:
        # Wrap API call with timeout to prevent hanging
        async with asyncio.timeout(DEFAULT_TIMEOUT):
            # Call unified _make_request() which handles all resilience + security features
            result, status_code = await _make_request(
                method=method,
                path=path,
                params=params,
                body=body,
                body_content_type=body_content_type,
                headers=headers,
                cookies=cookies,
                tool_name=tool_name,
                request_id=request_id,
                raw_querystring=raw_querystring,
            )

        latency_ms = (time.time() - start_time) * 1000.0

        logging.info(f"Tool completed: {tool_name}", extra={"request_id": request_id, "latency_ms": f"{latency_ms:.2f}"})

        # Normalize response to dict and return with status code
        # Use "value" key for consistency with generated response models
        if isinstance(result, dict):
            return result, status_code
        return {"value": result}, status_code

    except asyncio.TimeoutError as e:
        latency_ms = (time.time() - start_time) * 1000.0

        # Request timed out
        logging.error(
            f"Tool timeout: {tool_name}",
            extra={
                "request_id": request_id,
                "tool": tool_name,
                "method": method,
                "path": path,
                "timeout": DEFAULT_TIMEOUT,
                "latency_ms": f"{latency_ms:.2f}"
            }
        )

        # Raise exception with structured error message for consistency
        # FastMCP will catch this and set isError: true in MCP response
        timeout_message = (
            f"Tool: {tool_name}\n"
            f"Error: Request timed out after {DEFAULT_TIMEOUT} seconds\n"
            f"ID: {request_id}"
        )
        raise asyncio.TimeoutError(timeout_message) from e

    except ValueError:
        latency_ms = (time.time() - start_time) * 1000.0
        raise

    except ConnectionError:
        latency_ms = (time.time() - start_time) * 1000.0
        raise

    except Exception:
        latency_ms = (time.time() - start_time) * 1000.0
        raise

# ============================================================================
# Authentication
# ============================================================================

# Authentication scheme priority (most secure first)
AUTH_SCHEME_PRIORITY = [
    'oauth2',
    'openIdConnect',
    'http',
    'apiKey',
]

# Initialize authentication handlers at server startup
_auth_handlers: dict[str, Any] = {}
try:
    _auth_handlers["AuthZ"] = _auth.OAuth2Auth()
    logging.info("Authentication configured: AuthZ")
except ValueError as e:
    # Extract credential names from error message (first sentence before "Leave empty")
    error_msg = str(e).split("Leave empty")[0].strip()
    logging.warning(f"Credentials for AuthZ not configured: {error_msg}")
    _auth_handlers["AuthZ"] = None
try:
    _auth_handlers["apiKeyAuth"] = _auth.APIKeyAuth(env_var="API_KEY_AUTH_API_KEY", location="header", param_name="DD-API-KEY")
    logging.info("Authentication configured: apiKeyAuth")
except ValueError as e:
    # Extract credential names from error message (first sentence before "Leave empty")
    error_msg = str(e).split("Leave empty")[0].strip()
    logging.warning(f"Credentials for apiKeyAuth not configured: {error_msg}")
    _auth_handlers["apiKeyAuth"] = None
try:
    _auth_handlers["appKeyAuth"] = _auth.APIKeyAuth(env_var="APP_KEY_AUTH_API_KEY", location="header", param_name="DD-APPLICATION-KEY")
    logging.info("Authentication configured: appKeyAuth")
except ValueError as e:
    # Extract credential names from error message (first sentence before "Leave empty")
    error_msg = str(e).split("Leave empty")[0].strip()
    logging.warning(f"Credentials for appKeyAuth not configured: {error_msg}")
    _auth_handlers["appKeyAuth"] = None
try:
    _auth_handlers["bearerAuth"] = _auth.BearerTokenAuth(env_var="BEARER_TOKEN", token_format="Bearer")
    logging.info("Authentication configured: bearerAuth")
except ValueError as e:
    # Extract credential names from error message (first sentence before "Leave empty")
    error_msg = str(e).split("Leave empty")[0].strip()
    logging.warning(f"Credentials for bearerAuth not configured: {error_msg}")
    _auth_handlers["bearerAuth"] = None

# Warn only if NO auth handlers were successfully configured
if all(handler is None for handler in _auth_handlers.values()):
    logging.warning("Server will attempt unauthenticated requests (may fail if API requires auth)")

def _on_auth_failure() -> None:
    """Clear tokens on all auth handlers that support it (called on 401 response)."""
    for scheme_name, handler in _auth_handlers.items():
        if handler is not None and hasattr(handler, 'clear_token'):
            handler.clear_token()
            logging.info(f"Cleared token for auth scheme '{scheme_name}' after 401")

def _get_auth_for_operation(operation_id: str) -> dict[str, dict[str, str]]:
    """Get authentication for specific operation (handles multi-auth with OR/AND logic).

    Args:
        operation_id: The operation ID (tool name) to get auth for

    Returns:
        Dictionary with 'headers', 'params', 'cookies' keys containing auth data
    """
    result: dict[str, dict[str, str]] = {"headers": {}, "params": {}, "cookies": {}}

    # Get auth requirements for this operation from auth module
    # Map structure: operation_id -> [[scheme1], [scheme2, scheme3]] (OR of AND groups)
    required_schemes = _auth.OPERATION_AUTH_MAP.get(operation_id)

    if required_schemes is None:
        # CRITICAL: Operation missing from OPERATION_AUTH_MAP
        # This indicates a bug in auth config generation - operation should be in map
        # Do NOT fall back to global security - this masks bugs and creates security gaps
        logging.error(
            f"SECURITY ERROR: Operation '{operation_id}' not found in OPERATION_AUTH_MAP. "
            f"This indicates a bug in auth config generation. "
            f"All operations should be explicitly mapped. "
            f"Proceeding with no authentication - REQUEST WILL LIKELY FAIL."
        )
        # Return empty auth (will likely fail at API, but surfaces the bug)
        return result

    # Sort OR groups by security priority (most secure first)
    # Each OR group is sorted internally by scheme priority
    def get_scheme_priority(scheme_name: str) -> int:
        """Get priority index for scheme (lower = higher priority)."""
        try:
            return AUTH_SCHEME_PRIORITY.index(scheme_name)
        except ValueError:
            # Unknown scheme - put at end
            return len(AUTH_SCHEME_PRIORITY)

    # Sort each OR group by priority, then sort OR groups by their best (lowest) priority
    sorted_schemes = []
    for scheme_list in required_schemes:
        # Sort schemes within AND group by priority (most secure first)
        sorted_group = sorted(scheme_list, key=get_scheme_priority)
        sorted_schemes.append(sorted_group)

    # Sort OR groups by the priority of their first (most secure) scheme
    sorted_schemes.sort(key=lambda group: get_scheme_priority(group[0]) if group else float('inf'))

    # Try each OR group in priority order (most secure first)
    for scheme_list in sorted_schemes:
        headers = {}
        params = {}
        cookies = {}
        all_succeeded = True

        # Handle AND group (multiple schemes in same list - all must succeed)
        for scheme_name in scheme_list:
            handler = _auth_handlers.get(scheme_name)
            if not handler:
                # Handler not configured (env vars missing)
                all_succeeded = False
                logging.debug(f"Auth scheme '{scheme_name}' not configured for {operation_id}")
                break

            try:
                # Try all injection methods (headers, params, cookies)
                if hasattr(handler, 'get_auth_headers'):
                    headers.update(handler.get_auth_headers())
                if hasattr(handler, 'get_auth_params'):
                    params.update(handler.get_auth_params())
                if hasattr(handler, 'get_auth_cookies'):
                    cookies.update(handler.get_auth_cookies())
            except Exception as e:
                logging.debug(f"Auth scheme '{scheme_name}' failed for {operation_id}: {e}")
                all_succeeded = False
                break

        # If all schemes in AND group succeeded, use this auth
        if all_succeeded and (headers or params or cookies):
            result["headers"] = headers
            result["params"] = params
            result["cookies"] = cookies
            logging.debug(f"Using auth for {operation_id}: schemes={scheme_list}")
            return result

    # No auth configured or all OR groups failed
    if required_schemes and required_schemes != [[]]:
        logging.warning(f"No configured auth handler found for {operation_id} (requires: {required_schemes})")

    return result

